using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ───────────────────────────── AddItem ─────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllContributeToTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 3, price: 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantityAccumulates()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 0, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: -1, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.AddItem(null!, quantity: 1, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", quantity: 1, price: 10.00m));
    }

    // ──────────────────────────── RemoveItem ───────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_NoLongerInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 7.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("NO-SUCH-SKU"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.RemoveItem(null!));
    }

    // ─────────────────────────── CalculateTotal ────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsRemainingItems()
    {
        _cart.AddItem("A", quantity: 2, price: 15.00m);
        _cart.AddItem("B", quantity: 1, price: 25.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_ComputesCorrectly()
    {
        _cart.AddItem("BULK", quantity: 1000, price: 0.99m);

        Assert.AreEqual(990.00m, _cart.CalculateTotal());
    }

    // ──────────────────────────── ApplyCoupon ──────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("NOT-A-REAL-CODE"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"),
            "Applying the same coupon twice should not be allowed.");
    }

    // ────────────────────── Integration / Workflow ─────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("A", quantity: 2, price: 50.00m);  // 100
        _cart.AddItem("B", quantity: 1, price: 30.00m);  // 30
        _cart.RemoveItem("B");                            // -30
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total > 0m, "Total should still be positive.");
        Assert.IsTrue(total < 100.00m, "Coupon should have reduced the total.");
    }
}

